mapper.select:
SELECT id, application_id AS applicationId, company_id AS companyId, job_id AS jobId, user_id AS userId, hr_user_id AS hrUserId, interview_time AS interviewTime, interview_location AS interviewLocation, location_type AS locationType, contact_person AS contactPerson, contact_phone AS contactPhone, remark, status, candidate_remark AS candidateRemark, response_time AS responseTime, created_at AS createdAt, updated_at AS updatedAt FROM interviews
AND company_id = #{companyId} AND job_id = #{jobId} AND user_id = #{userId} AND hr_user_id = #{hrUserId} AND status = #{status} AND location_type = #{locationType}
AND contact_person LIKE CONCAT('%', #{contactPerson}, '%')
AND interview_time >= #{interviewTime}
ORDER BY interview_time ASC, id DESC

SELECT filtered.id, filtered.application_id AS applicationId, filtered.company_id AS companyId, filtered.job_id AS jobId, filtered.user_id AS userId, filtered.hr_user_id AS hrUserId, filtered.interview_time AS interviewTime, filtered.interview_location AS interviewLocation, filtered.location_type AS locationType, filtered.contact_person AS contactPerson, filtered.contact_phone AS contactPhone, filtered.remark, filtered.status, filtered.candidate_remark AS candidateRemark, filtered.response_time AS responseTime, filtered.created_at AS createdAt, filtered.updated_at AS updatedAt, u.realname AS userName, j.title AS jobTitle, u.avatar_url AS avatarUrl FROM ( SELECT * FROM interview
AND company_id = #{companyId}
AND job_id = #{jobId}
AND user_id = #{userId}
AND hr_user_id = #{hrUserId}
AND status = #{status}
AND location_type = #{locationType}
AND contact_person LIKE CONCAT('%', #{contactPerson}, '%')
AND interview_time >= #{interviewTime}
ORDER BY interview_time ASC, id DESC
) filtered INNER JOIN users u ON filtered.user_id = u.id INNER JOIN jobs j ON filtered.job_id = j.id ORDER BY filtered.interview_time ASC, filtered.id DESC

mapper.update:
UPDATE interview
application_id = #{applicationId}, company_id = #{companyId}, job_id = #{jobId}, user_id = #{userId}, hr_user_id = #{hrUserId}, interview_time = #{interviewTime}, interview_location = #{interviewLocation}, location_type = #{locationType}, contact_person = #{contactPerson}, contact_phone = #{contactPhone}, remark = #{remark}, status = #{status}, candidate_remark = #{candidateRemark}, response_time = #{responseTime}, created_at = #{createdAt}, updated_at = NOW()
WHERE id = #{id}
